// ─── Parse Webhook Body ───────────────────────────────────────────────
const item = $input.first();

// body.data comes as a nested JSON string
const rawData = item.json.body?.data || item.json.body || item.json;

let data;
try {
  data = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
} catch (e) {
  throw new Error(`Failed to parse body.data: ${e.message}`);
}

const project  = data.project             || {};
const fileInfo = data.file_info           || {};
const metadata = data.metadata            || {};
const criteria = data.evaluation_criteria || {};

// ── Validate ──
if (!project.id)           throw new Error('Missing required field: project.id');
if (!fileInfo.file_name)   throw new Error('Missing required field: file_info.file_name');
if (!item.binary?.cv_file) throw new Error('Missing CV file binary data');

// ── Build storage path (same pattern as WF1) ──
const now      = new Date();
const year     = now.getFullYear();
const month    = String(now.getMonth() + 1).padStart(2, '0');
const ts       = now.getTime();
const safeName = fileInfo.file_name.replace(/[^a-zA-Z0-9._-]/g, '_');
const mimeType = fileInfo.file_type || 'application/pdf';
const storageKey = `cv-files/manual/${year}/${month}/manual_${ts}_${safeName}`;

return [{
  json: {
    // ── Project / Job info ──
    hiring_project_id:     project.id,
    job_title:                 project.title                     || 'Unknown Position',
    department:                project.department                || '',
    location:                  project.location                  || '',
    job_type:                  project.job_type                  || '',
    required_skills:           JSON.stringify(project.required_skills || []),
    required_experience_years: project.required_experience_years || 0,
    required_education:        project.required_education         || '',
    job_description:           project.description               || '',
    job_status:                project.status                    || 'Active',

    // ── File info ──
    original_filename: fileInfo.file_name,
    file_size:         fileInfo.file_size   || 0,
    mime_type:         mimeType,
    file_uploaded_at:  fileInfo.uploaded_at || now.toISOString(),

    // ── Metadata ──
    source_platform: metadata.source_platform || 'Manual',
    uploaded_at:     metadata.uploaded_at     || now.toISOString(),
    criteria_set_id: metadata.criteria_set_id || null,

    // ── Evaluation criteria ──
    criteria_id:          criteria.id          || null,
    criteria_name:        criteria.name        || null,
    criteria_description: criteria.description || null,
    criteria_items:       JSON.stringify(criteria.items || []),

    // ── Storage ──
    storage_key: storageKey,
    cv_file_url: '',

    // ── Candidate placeholders (AI fills in WF5) ──
    email:     '',
    full_name: '',
    phone:     ''
  },
  binary: {
    cv_file: item.binary.cv_file
  }
}];

// ─── Set CV URL after successful upload ──────────────────────────────

// Previous parsed data (from webhook / earlier node)
const parsed = $('Code - Parse Webhook Body').first().json;
const binary = $('Code - Parse Webhook Body').first().binary;

// Upload response (current node input)
const uploadRes = $input.first().json;

// Encode key for safe URL
const encodedKey = encodeURI(uploadRes.Key);

// Construct public URL
const cvFileUrl = `https://dwkhucgwbbmgyxacfgir.supabase.co/storage/v1/object/public/${encodedKey}`;

return [{
  json: {
    // ✅ Keep all previous data
    ...parsed,

    // ✅ Keep upload response
    upload_id: uploadRes.Id,
    storage_key: uploadRes.Key,

    // ✅ Add computed fields
    cv_file_url: cvFileUrl,
    upload_success: true,

    // ✅ Optional useful metadata
    file_name: uploadRes.Key.split('/').pop(),
    file_path: uploadRes.Key,
    uploaded_at: new Date().toISOString()
  },

  binary: {
    // ✅ Keep binary if needed downstream
    cv_file: binary?.cv_file
  }
}];

// ─── Handle Upload Error ─────────────────────────────────────────────
const errorData = $input.first().json;
const parsed    = $('Code - Parse Webhook Body').first().json;

console.error('[Manual CV Intake] Upload failed:', JSON.stringify(errorData));

return [{
  json: {
    workflow_name:  'Workflow — Manual CV Intake',
    error_message:  errorData.message || 'CV upload to Supabase Storage failed',
    error_data:     JSON.stringify({
      job_post_id:  parsed.job_post_id,
      filename:     parsed.original_filename,
      storage_key:  parsed.storage_key,
      timestamp:    new Date().toISOString()
    })
  }
}];

// ─── Prepare WF5 payload ─────────────────────────────────────────────
const dbRow  = $input.first().json;
const cvData = $('Code - Set CV File URL').first().json;
const binary = $('Code - Set CV File URL').first().binary;

return [{
  json: {
    // ── Standard WF5 trigger fields ──
    email:           cvData.email          || '',
    full_name:       cvData.full_name      || '',
    phone:           cvData.phone          || '',
    source_platform: cvData.source_platform,
    cv_file_url:     cvData.cv_file_url,
    storage_key:     cvData.storage_key,
    applied_at:      cvData.uploaded_at,

    // ── Job requirements passed directly → WF5 skips Supabase lookup ──
    hiring_project_id:         cvData.hiring_project_id,
    job_description:           cvData.job_description,
    job_status:                cvData.job_status,
    job_title:                 cvData.job_title,
    department:                cvData.department || 'N/A', 
    required_skills:           cvData.required_skills,
    required_experience_years: cvData.required_experience_years,
    required_education:        cvData.required_education,
    skip_job_fetch:            true,
    location:                  cvData.location,

    // ── Tracking ──
    cv_evaluation_id:  dbRow.id             || null,
    criteria_set_id:   cvData.criteria_set_id,
    criteria_items:    cvData.criteria_items,
    original_filename: cvData.original_filename
  },
  binary: {
    cv_file: binary?.cv_file
  }
}];

// ─── Build final success response ────────────────────────────────────
const wf5Result = $input.first().json;

// FIX: Make sure these names match your actual nodes EXACTLY!
const cvData = $('Code - Set CV File URL').first().json;

// Use a try/catch or simple check to prevent the "Node doesn't exist" error
let dbId = null;
try {
  // Replace the name below with your ACTUAL Supabase node name
  dbId = $('Supabase - Insert CV Evaluation').first().json.id;
} catch (e) {
  console.log("Could not find Supabase node, skipping ID mapping");
}

return [{
  json: {
    success: true,
    message: 'CV received and screening completed successfully',
    data: {
      candidate_id:      wf5Result.candidate_id  || null,
      cv_evaluation_id:  wf5Result.cv_evaluation_id,
      job_post_id:       cvData.job_post_id,
      job_title:         cvData.job_title,
      original_filename: cvData.original_filename,
      cv_file_url:       cvData.cv_file_url,
      total_score:       wf5Result.total_score   || null,
      status:            wf5Result.status        || 'received',
      shortlisted:       wf5Result.shortlisted   || false,
      processing_status: 'completed',
      timestamp:         new Date().toISOString()
    }
  }
}];

const error = $input.first().json;
console.error('[Manual CV Intake] Fatal error:', error.message);

return [{
  json: {
    success: false,
    error:   error.message || 'Unknown error occurred',
    message: 'Failed to process CV data'
  }
}];

// ─── Prepare CV Binary for AI Processing ─────────────────────────────
// N8n stores binary data as base64 internally.
// We extract the base64 string and metadata to send to OpenAI GPT-4o.
//
// GPT-4o can read PDFs via the vision/image_url endpoint when
// sent as data:application/pdf;base64,<data>
//
// For DOCX files, we send as-is and let GPT-4o handle it.

const item = $input.first();
const triggerData = $('Trigger - AI Screening Entry').first().json;
const binaryData = item.binary?.cv_file || $('Trigger - AI Screening Entry').first().binary?.cv_file;

if (!binaryData) {
  return [{
    json: {
      ...triggerData,
      ...item.json,
      parse_error: true,
      error_message: 'No CV binary data found. Cannot proceed with AI parsing.'
    }
  }];
}

const base64CV = binaryData.data;
const mimeType = binaryData.mimeType || 'application/pdf';
const fileName = binaryData.fileName || 'cv.pdf';

// Truncate base64 if extremely large (>10MB) to avoid API limits
const maxBase64Length = 10 * 1024 * 1024 * 1.37; // ~10MB in base64
const truncated = base64CV.length > maxBase64Length;
const safeBase64 = truncated ? base64CV.substring(0, maxBase64Length) : base64CV;

return [{
  json: {
    ...triggerData,
    ...item.json,
    base64_cv: safeBase64,
    cv_mime_type: mimeType,
    cv_file_name: fileName,
    is_pdf: mimeType === 'application/pdf',
    is_docx: mimeType.includes('wordprocessingml'),
    is_text: mimeType === 'text/plain',
    cv_truncated: truncated,
    parse_error: false
  },
  binary: {
    cv_file: binaryData
  }
}];

// ─── Final Output Summary ─────────────────────────────────────────────
const item = $input.first().json;

console.log(`[AI Screening] Completed: ${item.parsed_name || item.full_name} | Score: ${item.total_score}% | Status: ${item.status} | Source: ${item.source_platform}`);

return [{
  json: {
    screening_complete: true,
    cv_evaluation_id:item.id,
    candidate_id: item.candidate_id,
    candidate_name: item.parsed_name || item.full_name,
    candidate_email: item.parsed_email || item.email,
    total_score: item.total_score,
    status: item.status,
    shortlisted: item.shortlisted,
    source_platform: item.source_platform,
    job_title: item.job_title,
    skills_matched: item.scoring_details?.matched_skills || [],
    skills_missing: item.scoring_details?.unmatched_skills || [],
    screened_at: item.screened_at
  }
}];

// ─────────────────────────────────────────────────────────────────────────────
// Parse AI CV Response — Production Grade FINAL
// FIXED:
//   ✅ AI scoring is source of truth
//   ✅ Incomplete AI responses NEVER fallback to shortlist
//   ✅ safeInt preserves null properly
//   ✅ shortlisted ALWAYS derived from status
//   ✅ fallback scoring only used when scoring block absent
//   ✅ total_score safely defaults to 0
//   ✅ education relevance support
//   ✅ score audit transparency
// ─────────────────────────────────────────────────────────────────────────────

const response    = $input.first().json || {};
const triggerData = $('Trigger - AI Screening Entry').first().json;
const reqData     = $('Code - Prepare CV for AI').first().json;

// ═════════════════════════════════════════════════════════════════════════════
// HELPERS
// ═════════════════════════════════════════════════════════════════════════════

function normalize(str) {
  return String(str || '').toLowerCase().trim();
}

function safeArray(val) {
  if (Array.isArray(val)) return val;

  if (!val) return [];

  try {
    const parsed = JSON.parse(val);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function parseSkills(raw) {
  if (!raw) return [];

  if (Array.isArray(raw)) {
    return raw.map(normalize);
  }

  const str = String(raw).trim();

  if (str.startsWith('{') && str.endsWith('}')) {
    return str
      .slice(1, -1)
      .split(',')
      .map(normalize);
  }

  try {
    const parsed = JSON.parse(str);
    return Array.isArray(parsed)
      ? parsed.map(normalize)
      : [];
  } catch {
    return [];
  }
}

// ✅ FIXED — preserves null values
function safeInt(val, fallback = null) {
  if (val === null || val === undefined || val === '') {
    return fallback;
  }

  const n = parseInt(val, 10);

  if (isNaN(n)) return fallback;

  return Math.min(100, Math.max(0, n));
}

function safeFloat(val, fallback = 0) {
  if (val === null || val === undefined || val === '') {
    return fallback;
  }

  const n = parseFloat(val);

  return isNaN(n) ? fallback : n;
}

// ═════════════════════════════════════════════════════════════════════════════
// API ERROR CHECK
// ═════════════════════════════════════════════════════════════════════════════

if (response.error) {
  return [{
    json: {
      ...triggerData,
      ...reqData,
      parse_error: true,
      error_message:
        `AI API error: ${
          response.error.message || JSON.stringify(response.error)
        }`
    }
  }];
}

// ═════════════════════════════════════════════════════════════════════════════
// EXTRACT RAW TEXT
// ═════════════════════════════════════════════════════════════════════════════

let rawText = '';

if (response.output) {
  rawText = response.output;

} else if (response.content?.parts?.[0]?.text) {
  rawText = response.content.parts[0].text;

} else if (response.candidates?.[0]?.content?.parts?.[0]?.text) {
  rawText = response.candidates[0].content.parts[0].text;

} else if (response.choices?.[0]?.message?.content) {
  rawText = response.choices[0].message.content;

} else if (response.text) {
  rawText = response.text;

} else if (
  Array.isArray($input.all()) &&
  $input.all()[0]?.json?.output
) {
  rawText = $input.all()[0].json.output;
}

if (!rawText) {
  return [{
    json: {
      ...triggerData,
      ...reqData,
      parse_error: true,
      error_message: 'AI returned empty response.'
    }
  }];
}

// ═════════════════════════════════════════════════════════════════════════════
// PARSE JSON
// ═════════════════════════════════════════════════════════════════════════════

let parsed = {};
let parseError = false;

try {
  let clean = rawText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();

  const jsonStart = clean.indexOf('{');
  const jsonEnd   = clean.lastIndexOf('}');

  if (jsonStart !== -1 && jsonEnd !== -1) {
    clean = clean.substring(jsonStart, jsonEnd + 1);
  }

  parsed = JSON.parse(clean);

} catch (e) {
  parseError = true;
  parsed = {};
}

if (parseError || parsed.parse_error) {
  return [{
    json: {
      ...triggerData,
      ...reqData,
      parse_error: true,
      error_message:
        parsed.error || 'Failed to parse AI JSON response.'
    }
  }];
}

// ═════════════════════════════════════════════════════════════════════════════
// EXTRACT PARSED DATA
// ═════════════════════════════════════════════════════════════════════════════

const parsedName     = parsed.full_name || triggerData.full_name || '';
const parsedEmail    = parsed.email || triggerData.email || '';
const parsedPhone    = parsed.phone || triggerData.phone || '';
const parsedLocation = parsed.location || '';
const parsedSummary  = parsed.summary || '';

const candidateSkills = parseSkills(parsed.skills);

const parsedEducation = safeArray(parsed.parsed_education);
const parsedCompanies = safeArray(parsed.parsed_companies);
const parsedProjects  = safeArray(parsed.parsed_projects);
const parsedCerts     = safeArray(parsed.parsed_certifications);

const criterionScores = safeArray(parsed.criterion_scores);

// ═════════════════════════════════════════════════════════════════════════════
// AI SCORING (PRIMARY SOURCE OF TRUTH)
// ═════════════════════════════════════════════════════════════════════════════

const aiScoring = parsed.scoring || {};

const aiSkillsScore     = safeInt(aiScoring.skills_match_score);
const aiExpScore        = safeInt(aiScoring.experience_score);
const aiEduScore        = safeInt(aiScoring.education_score);
const aiAdditionalScore = safeInt(aiScoring.additional_score);
const aiTotalScore      = safeInt(aiScoring.total_score);

const aiStatus          = aiScoring.status || null;
const aiShortlisted     = aiScoring.shortlisted ?? null;

// ✅ FIXED
// Only check if scoring object exists
// Do NOT require total_score
const hasAiScoring =
  parsed.scoring &&
  typeof parsed.scoring === 'object' &&
  Object.keys(parsed.scoring).length > 0;

// ═════════════════════════════════════════════════════════════════════════════
// AI SCORING DETAILS
// ═════════════════════════════════════════════════════════════════════════════

const aiDetails    = parsed.scoring_details || {};
const aiScoreAudit = parsed.score_audit || {};

const candExp = safeFloat(
  parsed.total_experience_years,
  0
);

const reqExp = safeFloat(
  parsed.required_exp ??
  aiDetails.required_exp ??
  reqData.required_experience_years,
  0
);

const expGap = safeFloat(
  aiDetails.exp_gap,
  candExp - reqExp
);

const projectCount =
  parseInt(aiDetails.project_count, 10) ||
  parsedProjects.length;

const certCount =
  parseInt(aiDetails.cert_count, 10) ||
  parsedCerts.length;

const eduLabel =
  aiDetails.edu_label || 'Not detected';

const eduRelevance =
  aiDetails.edu_field_relevance ?? null;

const eduRelevanceReason =
  aiDetails.edu_relevance_reason || '';

const aiMatchedSkills =
  safeArray(aiDetails.matched_skills);

const aiUnmatchedSkills =
  safeArray(aiDetails.unmatched_skills);

// ═════════════════════════════════════════════════════════════════════════════
// FALLBACK SCORING
// ONLY USED IF AI SCORING BLOCK IS ABSENT
// ═════════════════════════════════════════════════════════════════════════════

function fallbackSkillsScore(candidateSkills, reqData) {

  const reqSkills = parseSkills(reqData.required_skills);

  if (reqSkills.length === 0) {
    return 50;
  }

  const matched = reqSkills.filter(rs =>
    candidateSkills.some(cs =>
      cs.includes(rs) || rs.includes(cs)
    )
  );

  return Math.round(
    Math.min(
      (matched.length / reqSkills.length) * 100,
      100
    )
  );
}

function fallbackExpScore(candExp, reqExp) {

  if (reqExp === 0) {
    return candExp >= 0 ? 85 : 50;
  }

  if (candExp >= reqExp) {
    return 100;
  }

  return Math.round(
    Math.min((candExp / reqExp) * 70, 100)
  );
}

function fallbackEduScore(parsedEducation) {

  const eduText =
    JSON.stringify(parsedEducation).toLowerCase();

  if (eduText.includes('phd')) {
    return 75;
  }

  if (eduText.match(/master|mtech|m\.sc/)) {
    return 65;
  }

  if (eduText.match(/mba/)) {
    return 50;
  }

  if (eduText.match(/bachelor|btech|b\.e|bsc/)) {
    return 55;
  }

  if (eduText.match(/diploma|12th|hsc/)) {
    return 35;
  }

  return 40;
}

function fallbackAdditionalScore(projectCount, certCount) {

  return Math.min(
    50 +
    (projectCount > 0 ? 25 : 0) +
    (certCount > 0 ? 25 : 0),
    100
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// FINAL SCORE RESOLUTION
// ═════════════════════════════════════════════════════════════════════════════

let finalSkillsScore;
let finalExpScore;
let finalEduScore;
let finalAdditionalScore;
let finalTotalScore;

if (hasAiScoring) {

  finalSkillsScore =
    aiSkillsScore ??
    fallbackSkillsScore(candidateSkills, reqData);

  finalExpScore =
    aiExpScore ??
    fallbackExpScore(candExp, reqExp);

  finalEduScore =
    aiEduScore ??
    fallbackEduScore(parsedEducation);

  finalAdditionalScore =
    aiAdditionalScore ??
    fallbackAdditionalScore(projectCount, certCount);

  // ✅ FIXED
  finalTotalScore =
    aiTotalScore !== null
      ? aiTotalScore
      : 0;

} else {

  finalSkillsScore =
    fallbackSkillsScore(candidateSkills, reqData);

  finalExpScore =
    fallbackExpScore(candExp, reqExp);

  finalEduScore =
    fallbackEduScore(parsedEducation);

  finalAdditionalScore =
    fallbackAdditionalScore(projectCount, certCount);

  finalTotalScore = Math.round(
    (finalSkillsScore     * 0.40) +
    (finalExpScore        * 0.30) +
    (finalEduScore        * 0.20) +
    (finalAdditionalScore * 0.10)
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// STATUS + SHORTLISTED
// ═════════════════════════════════════════════════════════════════════════════

const SHORTLIST_THRESHOLD =
  reqData.shortlist_threshold ?? 65;

const SCREEN_THRESHOLD =
  reqData.screen_threshold ?? 45;

let finalStatus;

// ✅ FIXED
if (hasAiScoring) {

  finalStatus =
    aiStatus || 'Incomplete';

} else {

  if (finalTotalScore >= SHORTLIST_THRESHOLD) {
    finalStatus = 'Shortlisted';

  } else if (finalTotalScore >= SCREEN_THRESHOLD) {
    finalStatus = 'Screened';

  } else {
    finalStatus = 'Rejected';
  }
}

// ✅ ALWAYS DERIVED FROM STATUS
const finalShortlisted =
  finalStatus === 'Shortlisted';

// ═════════════════════════════════════════════════════════════════════════════
// SKILL MATCHING DETAILS
// ═════════════════════════════════════════════════════════════════════════════

const reqSkillsFallback =
  parseSkills(reqData.required_skills);

const noRequirements =
  reqSkillsFallback.length === 0;

const matchedSkills =
  aiMatchedSkills.length > 0
    ? aiMatchedSkills
    : noRequirements
      ? candidateSkills
      : reqSkillsFallback.filter(rs =>
          candidateSkills.some(cs =>
            cs.includes(rs) || rs.includes(cs)
          )
        );

const unmatchedSkills =
  aiUnmatchedSkills.length > 0
    ? aiUnmatchedSkills
    : noRequirements
      ? []
      : reqSkillsFallback.filter(
          rs => !matchedSkills.includes(rs)
        );

// ═════════════════════════════════════════════════════════════════════════════
// AI METADATA
// ═════════════════════════════════════════════════════════════════════════════

const tokensTotal =
  response.usageMetadata?.totalTokenCount ||
  response.usage?.total_tokens ||
  0;

const modelUsed =
  response.modelVersion ||
  response.model ||
  'unknown';

// ═════════════════════════════════════════════════════════════════════════════
// FINAL OUTPUT
// ═════════════════════════════════════════════════════════════════════════════

return [{
  json: {

    ...triggerData,
    ...reqData,

    // ── Parsed candidate data ─────────────────
    parsed_name:     parsedName,
    parsed_email:    parsedEmail,
    parsed_phone:    parsedPhone,
    parsed_location: parsedLocation,
    parsed_summary:  parsedSummary,

    parsed_skills:           candidateSkills,
    parsed_experience_years: candExp,

    parsed_education:
      JSON.stringify(parsedEducation),

    parsed_companies:      parsedCompanies,
    parsed_projects:       parsedProjects,
    parsed_certifications: parsedCerts,

    // ── Final scoring ─────────────────────────
    total_score: finalTotalScore,
    status:      finalStatus,
    shortlisted: finalShortlisted,

    skills_match_score:
      Math.round(finalSkillsScore || 0),

    experience_score:
      Math.round(finalExpScore || 0),

    education_score:
      Math.round(finalEduScore || 0),

    additional_score:
      Math.round(finalAdditionalScore || 0),

    // ── Scoring details ───────────────────────
    scoring_details: {

      matched_skills:   matchedSkills,
      unmatched_skills: unmatchedSkills,

      no_requirements: noRequirements,

      candidate_exp: candExp,
      required_exp:  reqExp,

      exp_gap:
        parseFloat((candExp - reqExp).toFixed(1)),

      project_count: projectCount,
      cert_count:    certCount,

      edu_label: eduLabel,

      edu_field_relevance:
        eduRelevance,

      edu_relevance_reason:
        eduRelevanceReason,

      job_level:
        parsed.job_level || 'unknown'
    },

    // ── Transparency ──────────────────────────
    score_audit: aiScoreAudit,

    override_reason:
      parsed.override_reason || null,

    shortlist_reason:
      parsed.shortlist_reason || null,

    reject_reason:
      parsed.reject_reason || null,

    criterion_scores:
      criterionScores,

    scoring_source:
      hasAiScoring ? 'ai' : 'fallback',

    // ── AI metadata ───────────────────────────
    ai_model: modelUsed,

