const item = $input.first().json;
const email = (item.email || item.parsed_email || '').toLowerCase().trim();
const phone = (item.phone || item.parsed_phone || '').replace(/\D/g, '');

if (!email) {
  return [{ json: { ...item, fingerprint: null, email_normalized: '', _skip_dedup: true } }];
}

const raw = `${email}::${phone}`;
let hash = 0;
for (let i = 0; i < raw.length; i++) {
  const char = raw.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash = hash & hash;
}
const fingerprint = `fp_${Math.abs(hash)}_${email.split('@')[0]}`;

return [{ json: { ...item, fingerprint, email_normalized: email, _skip_dedup: false } }];

